const hire = $input.first().json;
$execution.customData.set('hire_id', hire.hire_id);
$execution.customData.set('full_name', hire.full_name);
$execution.customData.set('workflow_stage', '04-account-provisioning');
return [{ json: hire }];

const crypto = require('crypto');
const hire = $input.first().json;
const plan = hire.provisioning_plan || {};
const results = {};

// Per-service isolation: one failure writes FAILED but does NOT throw.
async function provision(name, fn) {
  try {
    await fn();
    results[name] = 'SUCCESS';
  } catch (err) {
    results[name] = 'FAILED';
    results[`${name}_error`] = err.message;
    // Intentionally NOT rethrowing — per-service isolation.
  }
}

// GSuite Service Account JWT assertion flow (creates domain-wide delegation token)
async function getGSuiteToken() {
  const sa = JSON.parse($env['GSUITE_SERVICE_ACCOUNT_JSON']);
  const now = Math.floor(Date.now() / 1000);
  const h = Buffer.from(JSON.stringify({ alg: 'RS256', typ: 'JWT' })).toString('base64url');
  const p = Buffer.from(JSON.stringify({
    iss: sa.client_email,
    sub: $env['GSUITE_ADMIN_EMAIL'],
    scope: 'https://www.googleapis.com/auth/admin.directory.user',
    aud: 'https://oauth2.googleapis.com/token',
    iat: now,
    exp: now + 3600
  })).toString('base64url');
  const sign = crypto.createSign('RSA-SHA256');
  sign.update(`${h}.${p}`);
  const jwt = `${h}.${p}.${sign.sign(sa.private_key, 'base64url')}`;
  const r = await fetch('https://oauth2.googleapis.com/token', {
    method: 'POST',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: `grant_type=urn:ietf:params:oauth:grant-type:jwt-bearer&assertion=${jwt}`
  });
  const d = await r.json();
  if (!d.access_token) throw new Error(`GSuite token failed: ${JSON.stringify(d)}`);
  return d.access_token;
}

// 1. GSuite — Create user
await provision('gsuite', async () => {
  const token = await getGSuiteToken();
  const emailUser = `${hire.first_name.toLowerCase()}.${hire.last_name.toLowerCase()}`;
  const workEmail = `${emailUser}@[EMAIL_DOMAIN]`;
  const r = await fetch('https://admin.googleapis.com/admin/directory/v1/users', {
    method: 'POST',
    headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      primaryEmail: workEmail,
      name: { givenName: hire.first_name, familyName: hire.last_name },
      password: crypto.randomBytes(24).toString('hex'),
      changePasswordAtNextLogin: true,
      orgUnitPath: plan.gsuite_ou || '/Employees'
    })
  });
  if (!r.ok) {
    const e = await r.json();
    throw new Error(`GSuite: ${e.error?.message || r.status}`);
  }
  results.work_email = workEmail;
});

// 2. Slack — Invite to workspace
await provision('slack', async () => {
  const r = await fetch('https://slack.com/api/users.admin.invite', {
    method: 'POST',
    headers: { 'Authorization': 'Bearer [SLACK_BOT_TOKEN]', 'Content-Type': 'application/json' },
    body: JSON.stringify({
      email: hire.personal_email,
      real_name: hire.full_name,
      channels: (plan.slack_channels || []).join(',')
    })
  });
  const d = await r.json();
  if (!d.ok) throw new Error(`Slack: ${d.error}`);
});

// 3. Notion — Member onboarding page
await provision('notion', async () => {
  if (!plan.notion_page_id) { results.notion = 'SKIPPED'; return; }
  const r = await fetch('https://api.notion.com/v1/pages', {
    method: 'POST',
    headers: {
      'Authorization': 'Bearer [NOTION_INTEGRATION_TOKEN]',
      'Notion-Version': '2022-06-28',
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      parent: { page_id: plan.notion_page_id },
      properties: {
        title: { title: [{ text: { content: `${hire.full_name} — Onboarding (${hire.start_date})` } }] }
      }
    })
  });
  if (!r.ok) {
    const e = await r.json();
    throw new Error(`Notion: ${e.message || r.status}`);
  }
});

// 4. Conditional tool adapters — stubs per client
const conditionalTools = (plan.tools || []).filter(t => !['gsuite', 'slack', 'notion'].includes(t));
for (const tool of conditionalTools) {
  await provision(tool, async () => {
    switch (tool) {
      case 'github':  throw new Error('[GITHUB_ADAPTER] Stub — see SETUP.md §4.1');
      case 'linear':  throw new Error('[LINEAR_ADAPTER] Stub — see SETUP.md §4.2');
      case 'hubspot': throw new Error('[HUBSPOT_ADAPTER] Stub — see SETUP.md §4.3');
      case 'canva':   throw new Error('[CANVA_ADAPTER] Stub — see SETUP.md §4.4');
      default: results[tool] = 'SKIPPED — no adapter';
    }
  });
}

return [{
  json: {
    ...hire,
    provisioning_results: results,
    pipeline_started_at: hire.received_at
  }
}];
